namespace Forge.Api.Data.TrainingContent;

public class PlanningTraining : TrainingContentBase
{
    public PlanningTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Planning Cycles Overview",
            Slug = "planning-overview",
            Summary = "What planning cycles are, the two-week cadence, Day 1 planning flow, daily Top 3, and end-of-cycle rollover.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/planning"]""",
            Tags = """["planning","cycles","backlog"]""",
            ContentJson = """{"body":"## Planning Cycles Overview\n\nPlanning Cycles bring structure to your shop's workflow by organizing backlog jobs into focused, time-boxed sprints. Instead of an ever-growing list of work, you commit a manageable set of jobs to a cycle, track progress, and review results at the end.\n\n### What Is a Planning Cycle?\n\nA planning cycle is a fixed-duration window — typically two weeks (14 days) — during which your team commits to completing a specific set of jobs. Each cycle has:\n- A **name** (e.g., 'Sprint 12' or 'Week of Mar 11')\n- A **start date** and **end date**\n- Optional **goals** describing what the team aims to accomplish\n- A **status** that progresses through the lifecycle: Planning → Active → Completed\n\n### The Two-Week Cadence\n\nThe default cycle length is 14 days, but you can set any duration when creating a cycle. The system calculates duration automatically from your start and end dates. Most shops find two-week cycles hit the sweet spot — long enough to make meaningful progress, short enough to course-correct quickly.\n\n### Day 1: Planning Day\n\nThe first day of each cycle is Planning Day. This is when you:\n1. **Review the backlog** — the left panel shows all uncommitted jobs from the backlog, filterable by search and priority\n2. **Commit jobs** — drag jobs from the backlog panel on the left into the cycle panel on the right, or click the + button on each backlog job\n3. **Set goals** — describe what the team aims to accomplish this cycle\n4. **Prioritize** — reorder committed entries by dragging them up or down in the cycle panel\n5. **Activate the cycle** — move it from Planning to Active status when the team is aligned\n\n> **Known issue — the Activate button.** A new cycle is created in **Planning** status, and the design intent is that an **Activate** button appears on the cycle board to move it to **Active**. In the current build, that button's visibility is gated on a status value (`Draft`) that the server never produces — the server uses `Planning`, `Active`, and `Completed`. The practical effect: the **Activate button does not render today**, so a cycle stays in Planning. You can still work a Planning cycle exactly like an Active one — commit jobs, reorder, mark entries complete, and complete/roll over at the end (Complete is offered for Active cycles). The only thing you lose is the days-remaining countdown, which only shows for Active cycles. This is a tracked UI defect (status-name mismatch); the workflow is otherwise fully usable. Don't go looking for an Activate button that isn't there.\n\n### Who Can Do What (Roles)\n\nViewing a cycle is open to a broad set of roles — Admin, Manager, PM, Engineer, and Production Worker can all open the planning page and read cycles, the backlog, and progress. **Every change**, however, is restricted to **Admin and Manager** on the server: creating or editing a cycle, activating it, completing/rolling over, committing a job, removing a job, reordering entries, and marking an entry complete all require an Admin or Manager role. A Production Worker, Engineer, or PM who clicks a mutating action gets a 403 from the API. Think of planning as a manager-driven activity that the whole team can watch. (Planning Cycles also require the `CAP-PLAN-MRP` capability to be enabled for the install — if it's off, the page is hidden entirely.)\n\n### The Split-Panel Layout\n\nThe planning page uses a split-panel design:\n- **Left panel (Backlog):** Shows all jobs that haven't been committed to the current cycle. You can search by job number or title and filter by priority. Jobs already committed to the selected cycle are automatically hidden from the backlog.\n- **Right panel (Cycle Board):** Shows the selected cycle's details — name, date range, goals, progress bar, and the list of committed entries with their completion status.\n\nDrag a job from the left panel and drop it on the right panel to commit it. The backlog list updates instantly to hide the committed job.\n\n### Daily Top 3\n\nEach evening, the system prompts team members to identify their Top 3 priorities for the next day. This lightweight daily check-in keeps focus sharp without the overhead of a full standup meeting. The Top 3 feeds into the cycle board so everyone can see what's being worked on.\n\n### Tracking Progress\n\nOnce a cycle is active, you track progress directly on the cycle board:\n- **Mark entries complete** — click the check circle icon on any entry to mark it done\n- **Progress bar** — shows the percentage of completed entries (e.g., '5 / 12' and '42%')\n- **Days remaining** — displayed when the cycle is active, counting down to the end date\n- **Rolled-over badge** — entries that came from a previous cycle show a replay icon so you can see carryover work\n\n### End-of-Cycle: Completion and Rollover\n\nWhen the cycle ends, you have two options:\n\n1. **Complete & Roll Over** — marks the current cycle as Completed and automatically creates a new cycle. Any incomplete entries are carried over to the new cycle with the 'rolled over' badge. The new cycle starts the day after the old one ends and uses the same duration.\n\n2. **Complete (No Rollover)** — marks the cycle as Completed. Incomplete entries return to the backlog. No new cycle is created automatically.\n\nBoth options require confirmation via a dialog to prevent accidental completion.\n\n### Cycle Statuses\n\n| Status | Meaning |\n|--------|--------|\n| **Planning** | The default status of every new cycle. Jobs can be added, removed, reordered, and marked complete freely. You can complete or roll a Planning cycle over directly. (The Activate button intended to advance Planning → Active does not currently render — see the Known Issue note above.) |\n| **Active** | Cycle is in progress. Jobs can still be added or removed, the team is actively working, and the board shows a days-remaining countdown. The Complete & Roll Over and Complete actions appear for Active cycles. |\n| **Completed** | Cycle is finished. Read-only. All entries show their final completion state. |\n\n### When to Use Planning Cycles\n\n- When your backlog has more work than your team can tackle at once\n- When you want to create focus and commitment around a set of deliverables\n- When you need visibility into what was planned vs. what was actually completed\n- When you want to track how much work rolls over between cycles (a signal of over-commitment)","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Planning Cycles — Guided Tour",
            Slug = "planning-walkthrough",
            Summary = "A guided tour of the planning page: cycle selector, backlog panel, cycle board, drag-to-commit, and lifecycle actions.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/planning"]""",
            Tags = """["planning","walkthrough"]""",
            ContentJson = """{"appRoute":"/planning","startButtonLabel":"Tour Planning","steps":[{"element":".page-header app-select","popover":{"title":"Cycle Selector","description":"Switch between planning cycles using this dropdown. Each option shows the cycle name and its current status (Planning, Active, or Completed). The most recent or active cycle is selected by default when you load the page.","side":"bottom"}},{"element":"[data-testid='planning-new-cycle-btn']","popover":{"title":"New Cycle Button","description":"Click here to create a new planning cycle. You'll set a name, start date, end date, and optional goals. The default duration is 14 days — the end date is pre-filled two weeks from today.","side":"bottom"}},{"element":".backlog-panel__header","popover":{"title":"Backlog Panel Header","description":"The left panel shows your backlog — all jobs not yet committed to the selected cycle. The count tells you how many jobs are available. Jobs already committed to this cycle are automatically filtered out.","side":"right"}},{"element":".backlog-panel__filters","popover":{"title":"Backlog Filters","description":"Search by job number or title, and filter by priority (Urgent, High, Normal, Low). These filters help you find the right jobs to commit when your backlog is large.","side":"right"}},{"element":".backlog-panel__list","popover":{"title":"Backlog Job List","description":"Each job card shows the job number, title, current stage (color-coded chip), priority, and assignee avatar. Drag a job from here and drop it on the cycle panel to the right, or click the + button to commit it instantly.","side":"right"}},{"element":".cycle-panel","popover":{"title":"Cycle Board Panel","description":"The right panel shows the selected cycle's details. When no cycle is selected, you'll see an empty state with a prompt to create your first cycle. When a cycle is loaded, you see the header, progress bar, goals, and committed entries.","side":"left"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Planning Cycles Field Reference",
            Slug = "planning-field-reference",
            Summary = "Complete reference for every field, status, button, validation rule, and interaction in the Planning Cycles module.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/planning"]""",
            Tags = """["planning","reference"]""",
            ContentJson = """{"title":"Planning Cycles Field Reference","groups":[{"heading":"Cycle Form Fields (Create/Edit Dialog)","items":[{"label":"Name (required)","value":"Text input, max 100 characters (client) / 200 characters (server). Identifies the cycle. Examples: 'Sprint 12', 'Week of Mar 11', 'Q1 Final Push'. Must not be empty."},{"label":"Start Date (required)","value":"Date picker. When the cycle begins. For new cycles, defaults to today's date. Must be a valid date."},{"label":"End Date (required)","value":"Date picker. When the cycle ends. For new cycles, defaults to 14 days after the start date. Must be after the start date (server-validated)."},{"label":"Goals","value":"Textarea, optional, max 2000 characters (server). Free-form text describing what the team aims to accomplish this cycle. Displayed on the cycle board when present."}]},{"heading":"Cycle Entry Fields","items":[{"label":"Job Number","value":"Read-only. The job number of the committed job (e.g., 'J-1055'). Displayed in bold on each entry row."},{"label":"Job Title","value":"Read-only. The title of the committed job. Displayed next to the job number."},{"label":"Stage","value":"Read-only. The job's current kanban stage, shown as a color-coded chip matching the stage color."},{"label":"Priority","value":"Read-only. The job's priority level (Urgent, High, Normal, Low). Color-coded text."},{"label":"Assignee","value":"Read-only. The person assigned to the job. Shown as name text in the entry row. In the backlog panel, shown as an avatar with initials."},{"label":"Sort Order","value":"Drag-reorderable. Determines the display order of entries in the cycle board. Reorder by dragging the grip handle on the left of each entry."},{"label":"Committed At","value":"Auto-set timestamp when the job was added to the cycle. Not directly visible in the UI but tracked in the database."},{"label":"Completed At","value":"Timestamp set when the entry is marked complete. Entries with a completed timestamp show a filled check circle icon instead of the outline."},{"label":"Is Rolled Over","value":"Boolean flag. True when this entry was automatically carried from a previous cycle's incomplete work. Shown as a replay icon badge on the entry."}]},{"heading":"Cycle Statuses","items":[{"label":"Planning (chip)","value":"The starting status for every new cycle. Jobs can be freely added, removed, reordered, and marked complete. NOTE: the status chip styling keys the muted look off the string 'Draft', but the server emits 'Planning' — so the chip renders without the muted tint and the Activate button (also gated on 'Draft') does not appear. See the Activate row below."},{"label":"Active (primary/blue chip)","value":"The cycle is in progress. Shows the 'days remaining' countdown in the header. Jobs can still be added or removed. The Complete & Roll Over and Complete buttons are available for Active cycles."},{"label":"Completed (success/green chip)","value":"The cycle is finished. All entries are frozen in their final state. No further modifications. The cycle becomes a historical record of what was planned and accomplished."}]},{"heading":"Split Panel Layout","items":[{"label":"Left Panel — Backlog","value":"Shows all jobs from the backlog that are NOT already committed to the currently selected cycle. Filtered by search (job number or title) and priority dropdown. Jobs disappear from this list when committed and reappear when removed."},{"label":"Right Panel — Cycle Board","value":"Shows the selected cycle's full details: header (name, dates, days remaining, completion count, status chip), progress bar, goals section, and the list of committed entries. Also serves as the drop zone for drag-and-drop from the backlog."},{"label":"Drag-and-Drop","value":"CDK drag-and-drop connects the backlog list to the cycle panel. Drag a job card from the left and drop it anywhere on the right panel to commit it. Within the cycle board, drag entries by their grip handle to reorder."}]},{"heading":"Cycle Selector and Header","items":[{"label":"Cycle Dropdown","value":"Select component in the page header. Lists all cycles with their status in parentheses — e.g., 'Sprint 12 (Active)'. Changing the selection loads that cycle's details into the right panel."},{"label":"New Cycle Button","value":"Primary action button in the page header. Opens the cycle creation dialog with start date defaulting to today and end date to today + 14 days."}]},{"heading":"Buttons and Actions","items":[{"label":"+ (commit) button on backlog job","value":"Icon button on the right side of each backlog job card. Commits the job to the selected cycle immediately without drag-and-drop. Only visible when a cycle is selected. Tooltip: 'Commit to cycle'. data-testid: N/A (uses icon-btn class)."},{"label":"Edit (pencil icon)","value":"Icon button in the cycle panel actions. Opens the cycle dialog pre-filled with the current cycle's name, dates, and goals for editing. Tooltip: 'Edit cycle'."},{"label":"Activate (known UI defect — not rendering)","value":"Small action button intended to transition a Planning cycle to Active (no confirmation — immediate). Its visibility is gated on status === 'Draft', a value the server never returns (the server emits 'Planning'), so the button does NOT render in the current build. The /activate endpoint exists and works (POST /api/v1/planning-cycles/{id}/activate, Admin/Manager only); only the UI trigger is missing. Tracked as a status-name-mismatch defect. Workaround: a Planning cycle is fully usable — you can commit, reorder, complete entries, and complete/roll over without activating."},{"label":"Complete & Roll Over","value":"Small action button. Only shown when cycle is Active. Opens a confirmation dialog. On confirm: marks cycle Completed, creates a new cycle starting the day after the old one ends with the same duration, and copies all incomplete entries to the new cycle with the rolled-over flag."},{"label":"Complete (no rollover)","value":"Small action button. Only shown when cycle is Active. Opens a confirmation dialog with severity 'warn'. On confirm: marks cycle Completed. Incomplete entries return to the backlog. No new cycle is created."},{"label":"Mark Complete (check circle outline)","value":"Icon button on each uncommitted entry. Marks the entry as completed, setting the CompletedAt timestamp. The icon changes to a filled check circle. Tooltip: 'Mark complete'."},{"label":"Remove (X icon)","value":"Danger icon button on each entry. Opens a confirmation dialog (severity 'warn') asking to confirm removal. On confirm: removes the entry from the cycle and the job reappears in the backlog. Tooltip: 'Remove from cycle'."},{"label":"Drag Handle (grip icon)","value":"Drag handle on the left of each entry. Drag to reorder entries within the cycle. Reorder is sent to the API as a batch update of sort orders."},{"label":"Save (dialog)","value":"Primary button in the cycle creation/edit dialog. Disabled when form is invalid or save is in progress. Shows a spinning sync icon while saving. Creates or updates the cycle."},{"label":"Cancel (dialog)","value":"Secondary button in the cycle creation/edit dialog. Closes the dialog without saving."}]},{"heading":"Progress and Stats","items":[{"label":"Completion Count","value":"Displayed as 'X / Y' in the cycle board header (e.g., '5 / 12'). X = completed entries, Y = total entries."},{"label":"Progress Bar","value":"Horizontal bar below the header. Fill width equals the completion percentage. Label shows the integer percentage (e.g., '42%')."},{"label":"Days Remaining","value":"Shown only when the cycle is Active. Counts calendar days from today to the end date. Shows '0' on the last day. Not shown for Planning or Completed cycles."},{"label":"Backlog Count","value":"Shown in the backlog panel header as 'N jobs'. Reflects the filtered count after excluding committed jobs and applying search/priority filters."}]},{"heading":"Validation Rules","items":[{"label":"Name","value":"Required. Max 100 characters (client), 200 characters (server). Cannot be empty."},{"label":"Start Date","value":"Required. Must be a valid date."},{"label":"End Date","value":"Required. Must be a valid date. Server validates that end date is after start date."},{"label":"Goals","value":"Optional. Max 2000 characters (server). No format restrictions."},{"label":"Duration Days","value":"Auto-calculated from (End Date - Start Date). Sent to the API on creation. Used when creating rollover cycles to preserve the same cycle length."},{"label":"Submit button popover","value":"When the form is invalid, hovering over the Save button shows a validation popover listing which fields need attention (Name, Start Date, End Date)."}]},{"heading":"Roles & Permissions (Who Can Do What)","items":[{"label":"View / read (open the page, read cycles + backlog + progress)","value":"Allowed for Admin, Manager, PM, Engineer, and Production Worker. The planning page and all read endpoints (list cycles, current cycle, cycle detail) are open to this broader role set so the whole team can watch the plan."},{"label":"Create a cycle","value":"Admin or Manager only. POST /api/v1/planning-cycles. A Production Worker, Engineer, or PM gets a 403."},{"label":"Edit a cycle (name/dates/goals)","value":"Admin or Manager only. PUT /api/v1/planning-cycles/{id}."},{"label":"Activate a cycle","value":"Admin or Manager only. POST .../{id}/activate. (The UI trigger is currently missing — see the Activate button row.)"},{"label":"Complete / Roll over a cycle","value":"Admin or Manager only. POST .../{id}/complete."},{"label":"Commit a job to the cycle","value":"Admin or Manager only. POST .../{id}/entries. The + button and drag-to-commit call this endpoint, so a worker's attempt is rejected at the API."},{"label":"Remove a job from the cycle","value":"Admin or Manager only. DELETE .../{id}/entries/{jobId}."},{"label":"Reorder entries","value":"Admin or Manager only. PUT .../{id}/entries/order."},{"label":"Mark an entry complete","value":"Admin or Manager only. POST .../{id}/entries/{jobId}/complete."},{"label":"Capability gate","value":"All planning endpoints also require CAP-PLAN-MRP. If that capability is disabled for the install, the planning area is hidden entirely regardless of role."}]},{"heading":"Empty States","items":[{"label":"No cycle selected","value":"Right panel shows an empty state with icon 'event_note', message 'No cycle selected', and a 'Create first cycle' action button."},{"label":"No jobs committed","value":"Cycle board entries area shows an empty state with icon 'assignment' and message 'No jobs committed'."},{"label":"No available jobs in backlog","value":"Backlog list shows an empty state with icon 'inbox' and message 'No available jobs'."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Planning Cycles Knowledge Check",
            Slug = "planning-quiz",
            Summary = "Test your knowledge of planning cycles: cadence, statuses, drag-to-commit, rollover, Top 3, and common workflows.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/planning"]""",
            Tags = """["planning","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"pl1","text":"What is the default duration of a planning cycle in QB Engineer?","options":[{"id":"a","text":"7 days (one week)"},{"id":"b","text":"14 days (two weeks)","isCorrect":true},{"id":"c","text":"30 days (one month)"},{"id":"d","text":"There is no default — you must always set it manually"}],"explanation":"The default cycle duration is 14 days (two weeks). When creating a new cycle, the end date is automatically pre-filled to 14 days after the start date. You can adjust this to any duration that works for your team."},{"id":"pl2","text":"You're on the planning page and want to add a backlog job to the current cycle. What are the two ways to do this?","options":[{"id":"a","text":"Drag the job from the left backlog panel to the right cycle panel, or click the + button on the job card","isCorrect":true},{"id":"b","text":"Right-click the job and select 'Add to Cycle', or use the keyboard shortcut Ctrl+A"},{"id":"c","text":"Open the job detail dialog and click 'Commit to Cycle', or edit the cycle and add jobs from a dropdown"},{"id":"d","text":"Navigate to the Kanban board and move the job to a 'Planned' column, or use the Backlog page's bulk action"}],"explanation":"The planning page supports two methods for committing jobs: drag-and-drop from the backlog panel (left) to the cycle panel (right), or clicking the + icon button on the right side of each backlog job card."},{"id":"pl3","text":"A planning cycle has status 'Planning'. What does this mean and what can you do?","options":[{"id":"a","text":"The cycle is in progress and the team is actively working on committed jobs"},{"id":"b","text":"It is the default status of a new cycle — you can add, remove, reorder, and complete jobs, and even complete/roll over the cycle, all without activating it","isCorrect":true},{"id":"c","text":"The cycle has been completed and is now in a read-only review state"},{"id":"d","text":"The cycle is paused and waiting for manager approval before it can be activated"}],"explanation":"Planning is the default status of every new cycle, and it is fully workable: add, remove, reorder, and mark entries complete, and complete or roll the cycle over from here. An Activate button was meant to move Planning → Active, but it's gated on a 'Draft' status the server never produces, so it doesn't render today — a tracked UI defect. The only thing Activate would add is the days-remaining countdown."},{"id":"pl4","text":"You complete a cycle and choose 'Complete & Roll Over'. What happens to the three incomplete jobs?","options":[{"id":"a","text":"They are permanently removed and must be re-created from scratch"},{"id":"b","text":"They stay in the completed cycle and are marked as failed"},{"id":"c","text":"They are automatically copied to a new cycle that starts the day after the old one ends, flagged with a rolled-over badge","isCorrect":true},{"id":"d","text":"They return to the backlog and lose all planning context"}],"explanation":"Complete & Roll Over creates a new cycle starting the day after the completed one ends, using the same duration. All incomplete entries are copied to the new cycle with the IsRolledOver flag set to true, shown as a replay icon badge in the UI."},{"id":"pl5","text":"How does the backlog panel on the left know which jobs to show?","options":[{"id":"a","text":"It shows all jobs in the system regardless of status or cycle"},{"id":"b","text":"It shows all backlog jobs that are NOT already committed to the currently selected cycle, filtered by search and priority","isCorrect":true},{"id":"c","text":"It only shows jobs assigned to the logged-in user"},{"id":"d","text":"It shows jobs from the Kanban board's first column only"}],"explanation":"The backlog panel shows all jobs from the backlog minus any that are already committed to the selected cycle. It also respects the search (by job number or title) and priority filters. When you commit a job, it instantly disappears from the backlog list."},{"id":"pl6","text":"You want to change the order of committed jobs in the cycle board. How do you do this?","options":[{"id":"a","text":"Click column headers to sort alphabetically or by priority"},{"id":"b","text":"Drag entries by the grip handle (drag_indicator icon) on the left side of each entry to reorder them","isCorrect":true},{"id":"c","text":"Open the cycle edit dialog and use an 'Order' dropdown for each entry"},{"id":"d","text":"You cannot reorder entries — they are always sorted by the date they were committed"}],"explanation":"Each entry in the cycle board has a drag handle (grip icon) on its left side. Drag entries up or down to change their priority order. The reorder is saved to the API as a batch update of sort orders."},{"id":"pl7","text":"What information does the cycle board header display when a cycle is Active?","options":[{"id":"a","text":"Only the cycle name and status"},{"id":"b","text":"Cycle name, date range (start – end), days remaining countdown, completion count (X / Y), and a status chip","isCorrect":true},{"id":"c","text":"A Gantt chart showing each job's timeline within the cycle"},{"id":"d","text":"The cycle name and a list of team members assigned to the cycle"}],"explanation":"The active cycle board header shows the cycle name, date range, days remaining (counting down to end date), completion count (e.g., '5 / 12'), and a color-coded status chip (blue for Active). A progress bar below shows the completion percentage."},{"id":"pl8","text":"You click 'Complete' (without rollover) on an active cycle that has 4 incomplete jobs. What happens to those jobs?","options":[{"id":"a","text":"They are deleted from the system"},{"id":"b","text":"They remain in the completed cycle marked as incomplete, and return to the backlog for future planning","isCorrect":true},{"id":"c","text":"They are automatically moved to the next active cycle"},{"id":"d","text":"They are archived and cannot be accessed again"}],"explanation":"Completing a cycle without rollover marks the cycle as Completed. The incomplete entries stay on the cycle record as historical data, and the jobs themselves return to the backlog where they can be committed to a future cycle."},{"id":"pl9","text":"What fields are required when creating a new planning cycle?","options":[{"id":"a","text":"Name, Start Date, End Date, and Goals are all required"},{"id":"b","text":"Name, Start Date, and End Date are required. Goals is optional.","isCorrect":true},{"id":"c","text":"Only the Name is required — dates are auto-calculated from the team calendar"},{"id":"d","text":"Start Date and End Date are required. Name is auto-generated from the date range."}],"explanation":"Creating a cycle requires a Name, Start Date, and End Date. The Goals field is optional (max 2000 characters). The End Date must be after the Start Date — this is validated on the server. Duration Days is auto-calculated from the date difference."},{"id":"pl10","text":"A committed entry in the cycle board shows a replay icon badge. What does this indicate?","options":[{"id":"a","text":"The job has been restarted after being previously completed"},{"id":"b","text":"The entry was automatically rolled over from a previous cycle's incomplete work","isCorrect":true},{"id":"c","text":"The job is on hold and waiting for materials"},{"id":"d","text":"The entry has been edited since it was originally committed"}],"explanation":"The replay icon badge indicates the entry was rolled over from a previous cycle. When you use 'Complete & Roll Over', incomplete entries from the finished cycle are copied to the new cycle with the IsRolledOver flag set to true."},{"id":"pl11","text":"You want to remove a job from the current cycle without completing it. What happens?","options":[{"id":"a","text":"The job is immediately removed with no confirmation"},{"id":"b","text":"A confirmation dialog appears (severity: warn). On confirm, the job is removed from the cycle and reappears in the backlog panel.","isCorrect":true},{"id":"c","text":"The job is archived and removed from both the cycle and the backlog"},{"id":"d","text":"You cannot remove jobs from a cycle — you can only mark them complete or wait for the cycle to end"}],"explanation":"Clicking the X (remove) button on a cycle entry opens a confirmation dialog with severity 'warn' asking you to confirm the removal. If confirmed, the entry is deleted from the cycle and the job reappears in the backlog panel on the left."},{"id":"pl12","text":"The progress bar on the cycle board shows '75%' and the count shows '6 / 8'. What does this tell you?","options":[{"id":"a","text":"75% of the cycle's time has elapsed and 6 out of 8 team members are assigned"},{"id":"b","text":"6 out of 8 committed entries have been marked complete, which is 75% of the total","isCorrect":true},{"id":"c","text":"6 jobs are in progress and 8 are in the backlog, with 75% of the backlog committed"},{"id":"d","text":"The cycle budget is 75% spent with 6 of 8 purchase orders fulfilled"}],"explanation":"The completion count 'X / Y' shows completed entries vs. total committed entries. The progress bar fills to the corresponding percentage. In this case, 6 of 8 entries are marked complete (6/8 = 75%)."},{"id":"pl13","text":"A Production Worker (or Engineer/PM) opens the planning page and tries to commit a backlog job to the current cycle. What happens?","options":[{"id":"a","text":"It works the same as for a manager — any role that can see a cycle can also change it"},{"id":"b","text":"The action is rejected by the server with a 403 — committing, removing, reordering, completing entries, and creating/activating/completing cycles all require an Admin or Manager role","isCorrect":true},{"id":"c","text":"The job is committed but flagged for manager approval before it counts"},{"id":"d","text":"The planning page never loads for non-managers, so the question can't arise"}],"explanation":"Reading a cycle is open to Admin, Manager, PM, Engineer, and Production Worker, but EVERY mutation — create, edit, activate, complete/roll over, commit a job, remove a job, reorder entries, and mark an entry complete — is restricted to Admin and Manager on the server. A non-manager who triggers a mutating action gets a 403. Planning is a manager-driven activity the whole team can watch."},{"id":"pl14","text":"You created a new cycle and want to move it from Planning to Active, but you can't find an Activate button anywhere on the cycle board. What's going on?","options":[{"id":"a","text":"You must first commit at least three jobs before the Activate button appears"},{"id":"b","text":"The Activate button is a known UI defect — its visibility is gated on a 'Draft' status the server never returns (the server uses 'Planning'), so it doesn't render. The cycle is still fully usable in Planning status.","isCorrect":true},{"id":"c","text":"Only system administrators can see the Activate button; managers cannot"},{"id":"d","text":"Cycles activate automatically at midnight on their start date, so there is no button"}],"explanation":"The Activate button's @if is gated on status === 'Draft', but the server emits 'Planning', 'Active', or 'Completed' — never 'Draft'. So the button never renders. This is a tracked status-name-mismatch defect. The /activate endpoint itself works; only the UI trigger is missing. A Planning cycle is fully workable in the meantime — the only thing you lose without activating is the days-remaining countdown."}]}"""
        });

        Log.Information("Seeded Planning Cycles training modules");
    }
}
